// Extract clean data from Telegram message payload
const msg = $input.first().json.message;

if (!msg || !msg.text) {
  return [{ json: { valid: false, text: '', chatId: null, customerName: 'Unknown' } }];
}

const firstName = msg.from?.first_name || '';
const lastName = msg.from?.last_name || '';
const customerName = (firstName + ' ' + lastName).trim() || 'Customer';

return [{
  json: {
    valid: true,
    chatId: msg.chat.id,
    customerId: msg.from?.id,
    customerName,
    text: msg.text.trim(),
    messageId: msg.message_id
  }
}];

const data = $input.first().json;
const text = data.text.toLowerCase().trim();

// ── MENU (edit item names & prices here) ──────────────────────────
const MENU = {
  'idli':        15,
  'dosa':        20,
  'masala dosa': 35,
  'pongal':      18,
  'vada':        12,
  'sambar rice': 40,
  'curd rice':   35,
  'chapati':     15,
  'parota':      20,
  'fried rice':  60,
  'meals':       80
};
// ─────────────────────────────────────────────────────────────────

// Check for menu / help requests
const menuKeywords = ['menu', 'items', 'list', 'price', 'what do you have', 'available', 'hi', 'hello', 'start'];
if (menuKeywords.some(k => text.includes(k))) {
  return [{ json: { ...data, intent: 'menu', items: [], orderTotal: 0, MENU } }];
}

// Parse order — try longest item names first to avoid partial matches
const items = [];
const sortedItems = Object.keys(MENU).sort((a, b) => b.length - a.length);

for (const item of sortedItems) {
  const escaped = item.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const patterns = [
    new RegExp(`(\\d+)\\s*x?\\s*${escaped}`, 'i'),  // "2 idli", "2x idli"
    new RegExp(`${escaped}\\s*x?\\s*(\\d+)`, 'i')   // "idli 2", "idli x2"
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      const qty = parseInt(match[1]);
      items.push({
        item,
        qty,
        unitPrice: MENU[item],
        total: qty * MENU[item]
      });
      break;
    }
  }
}

// If no quantity given but item name found, default qty = 1
if (items.length === 0) {
  for (const item of sortedItems) {
    if (text.includes(item)) {
      items.push({ item, qty: 1, unitPrice: MENU[item], total: MENU[item] });
    }
  }
}

const orderTotal = items.reduce((sum, i) => sum + i.total, 0);
const intent = items.length > 0 ? 'order' : 'unknown';

return [{ json: { ...data, intent, items, orderTotal, MENU } }];

const data = $input.first().json;

// Generate a short order ID
const orderId = 'ORD-' + Date.now().toString().slice(-6);

// IST timestamp
const now = new Date();
const ist = new Date(now.getTime() + 5.5 * 60 * 60 * 1000);
const orderDate = ist.toISOString().replace('T', ' ').substring(0, 19);

// Build a readable summary string for Sheets
const itemSummary = data.items
  .map(i => `${i.item} x${i.qty} = ₹${i.total}`)
  .join('; ');

// Build a pretty message for Telegram
const itemLines = data.items
  .map(i => `  • ${i.item} × ${i.qty}  —  ₹${i.total}`)
  .join('\n');

return [{
  json: {
    ...data,
    orderId,
    orderDate,
    itemSummary,
    itemLines,
    status: 'received'
  }
}];
